mapper.select:
SELECT r.*, u.name AS reporter_name FROM reports r JOIN users u ON u.user_id = r.reporter_id LEFT JOIN products p ON p.product_id = r.target_id AND target_type = 'PRODUCT' LEFT JOIN reviews rv ON rv.review_id = r.target_id AND target_type = 'REVIEW' LEFT JOIN qnas q ON q.qna_id = r.target_id AND target_type = 'QNA'
r.status = #{status}
AND ( r.reason LIKE CONCAT("%", #{keyword} ,"%") OR u.name LIKE CONCAT("%", #{keyword} ,"%") )
